//! Reads variables and recipes out of a Makefile generated by CPython's
//! `./configure` (via its internal `makesetup` pass), so build.zig can drive
//! compilation directly instead of invoking `make`.
//!
//! `./configure` alone (no `make`) already fully resolves which optional
//! extension modules are available on this system and expands every
//! per-module CFLAGS/LDFLAGS/object list into the generated Makefile text.
//! We treat that file purely as data: never executed, only parsed.

const std = @import("std");

const Makefile = @This();

text: []const u8,

fn matchAssign(line: []const u8, name: []const u8) ?[]const u8 {
    if (!std.mem.startsWith(u8, line, name)) return null;
    var rest = line[name.len..];
    rest = std.mem.trimStart(u8, rest, " \t");
    if (rest.len > 0 and rest[0] == ':') rest = rest[1..]; // ":=" form
    if (rest.len == 0 or rest[0] != '=') return null;
    return rest[1..];
}

fn hasContinuation(s: []const u8) bool {
    const t = std.mem.trimEnd(u8, s, " \t");
    return t.len > 0 and t[t.len - 1] == '\\';
}

fn stripContinuation(s: []const u8) []const u8 {
    const t = std.mem.trimEnd(u8, s, " \t");
    if (t.len > 0 and t[t.len - 1] == '\\') return std.mem.trimEnd(u8, t[0 .. t.len - 1], " \t");
    return t;
}

/// Raw (unexpanded) value of a "NAME = value" / "NAME := value" assignment,
/// following backslash-newline continuations. Empty string if undefined.
pub fn getRaw(mk: Makefile, gpa: std.mem.Allocator, name: []const u8) []const u8 {
    var out: std.ArrayList(u8) = .empty;
    var lines = std.mem.splitScalar(u8, mk.text, '\n');
    var found = false;
    while (lines.next()) |line| {
        if (!found) {
            if (line.len == 0 or line[0] == '\t' or line[0] == '#') continue;
            const val = matchAssign(line, name) orelse continue;
            found = true;
            out.appendSlice(gpa, stripContinuation(std.mem.trimStart(u8, val, " \t"))) catch @panic("OOM");
            if (!hasContinuation(val)) break;
            continue;
        }
        out.append(gpa, ' ') catch @panic("OOM");
        out.appendSlice(gpa, stripContinuation(std.mem.trimStart(u8, line, " \t"))) catch @panic("OOM");
        if (!hasContinuation(line)) break;
    }
    return out.items;
}

fn expandDepth(mk: Makefile, gpa: std.mem.Allocator, raw: []const u8, depth: u8) []const u8 {
    if (depth > 24) @panic("Makefile variable expansion too deep (cycle?)");
    var out: std.ArrayList(u8) = .empty;
    var i: usize = 0;
    while (i < raw.len) {
        const closer: u8 = if (i + 1 < raw.len and raw[i + 1] == '(') ')' else if (i + 1 < raw.len and raw[i + 1] == '{') '}' else 0;
        if (raw[i] == '$' and closer != 0) {
            const close = std.mem.indexOfScalarPos(u8, raw, i + 2, closer) orelse {
                out.append(gpa, raw[i]) catch @panic("OOM");
                i += 1;
                continue;
            };
            const name = raw[i + 2 .. close];
            const inner_raw = mk.getRaw(gpa, name);
            const inner_expanded = mk.expandDepth(gpa, inner_raw, depth + 1);
            out.appendSlice(gpa, inner_expanded) catch @panic("OOM");
            i = close + 1;
            continue;
        }
        out.append(gpa, raw[i]) catch @panic("OOM");
        i += 1;
    }
    return out.items;
}

/// Recursively expands $(NAME) references found inside `raw`.
pub fn expand(mk: Makefile, gpa: std.mem.Allocator, raw: []const u8) []const u8 {
    return mk.expandDepth(gpa, raw, 0);
}

/// Fully resolved (expanded) value of a Makefile variable.
pub fn get(mk: Makefile, gpa: std.mem.Allocator, name: []const u8) []const u8 {
    return mk.expand(gpa, mk.getRaw(gpa, name));
}

pub fn tokens(gpa: std.mem.Allocator, s: []const u8) [][]const u8 {
    var list: std.ArrayList([]const u8) = .empty;
    var it = std.mem.tokenizeAny(u8, s, " \t");
    while (it.next()) |tok| list.append(gpa, tok) catch @panic("OOM");
    return list.toOwnedSlice(gpa) catch @panic("OOM");
}

/// Converts a whitespace-separated list of object paths (e.g. "Modules/foo.o
/// Python/bar.o") into their corresponding source file paths, replacing a
/// trailing ".o" with ".c". Strips a literal "$(srcdir)/" prefix (in-tree
/// build: srcdir is ".").
pub fn objsToSources(gpa: std.mem.Allocator, objs: []const u8) [][]const u8 {
    var list: std.ArrayList([]const u8) = .empty;
    var it = std.mem.tokenizeAny(u8, objs, " \t");
    while (it.next()) |tok| {
        var path = tok;
        if (std.mem.startsWith(u8, path, "$(srcdir)/")) path = path["$(srcdir)/".len..];
        if (!std.mem.endsWith(u8, path, ".o")) continue;
        const src = std.fmt.allocPrint(gpa, "{s}c", .{path[0 .. path.len - 1]}) catch @panic("OOM");
        list.append(gpa, src) catch @panic("OOM");
    }
    return list.toOwnedSlice(gpa) catch @panic("OOM");
}

pub const FreezeEntry = struct {
    name: []const u8,
    src: []const u8,
    out: []const u8,
    bootstrap: bool,
};

/// Parses every `$(FREEZE_MODULE_BOOTSTRAP) NAME SRC OUT` / `$(FREEZE_MODULE)
/// NAME SRC OUT` recipe line, in file order. This is the exact same list
/// CPython's own Makefile uses to freeze importlib/getpath/stdlib bootstrap
/// modules; reading it back out avoids re-deriving module-name-from-path
/// logic that CPython itself might change between versions.
pub fn freezeEntries(mk: Makefile, gpa: std.mem.Allocator) []FreezeEntry {
    var list: std.ArrayList(FreezeEntry) = .empty;
    var lines = std.mem.splitScalar(u8, mk.text, '\n');
    while (lines.next()) |line| {
        if (line.len == 0 or line[0] != '\t') continue;
        const rest_bootstrap = matchMacroCall(line, "$(FREEZE_MODULE_BOOTSTRAP)");
        const bootstrap = rest_bootstrap != null;
        const rest = rest_bootstrap orelse matchMacroCall(line, "$(FREEZE_MODULE)") orelse continue;
        const toks = tokens(gpa, rest);
        if (toks.len != 3) continue;
        var src = toks[1];
        if (std.mem.startsWith(u8, src, "$(srcdir)/")) src = src["$(srcdir)/".len..];
        list.append(gpa, .{ .name = toks[0], .src = src, .out = toks[2], .bootstrap = bootstrap }) catch @panic("OOM");
    }
    return list.toOwnedSlice(gpa) catch @panic("OOM");
}

fn matchMacroCall(line: []const u8, macro: []const u8) ?[]const u8 {
    const trimmed = std.mem.trimStart(u8, line, " \t");
    if (!std.mem.startsWith(u8, trimmed, macro)) return null;
    return trimmed[macro.len..];
}

pub const ModuleRule = struct {
    /// Prerequisite tokens (before ';'), typically the module's own object file(s).
    prereqs: [][]const u8,
    /// Recipe tokens (after ';'), fully $(...)/${...}-expanded: linker invocation,
    /// the module's own objects again, any bundled static-lib archives, and
    /// extra -l/-L flags.
    recipe: [][]const u8,
};

/// Finds the compile flags actually used to build a single object file, by
/// locating its rule (`<obj>: <deps>[; <recipe>]`, recipe either inline after
/// ';' or on the following backslash-continued tab lines) and pulling out
/// everything between `$(CC)`/`$(LINKCC)` and ` -c `. Most modules delegate
/// this to a `MODULE_<NAME>_CFLAGS`-style variable, but not all do (e.g.
/// sha3module.o inlines its own `-I` flag) -- reading the real recipe avoids
/// having to special-case every exception to that convention.
pub fn findObjectFlags(mk: Makefile, gpa: std.mem.Allocator, obj_path: []const u8) ?[]const u8 {
    var lines = std.mem.splitScalar(u8, mk.text, '\n');
    while (lines.next()) |line| {
        if (!std.mem.startsWith(u8, line, obj_path)) continue;
        const after = line[obj_path.len..];
        if (after.len == 0 or after[0] != ':') continue;

        if (std.mem.indexOfScalar(u8, line, ';')) |semi| {
            return extractCcFlags(mk, gpa, line[semi + 1 ..]);
        }
        var recipe: std.ArrayList(u8) = .empty;
        var line_continues = true;
        while (line_continues) {
            const next_line = lines.next() orelse break;
            if (next_line.len == 0 or next_line[0] != '\t') break;
            recipe.append(gpa, ' ') catch @panic("OOM");
            recipe.appendSlice(gpa, stripContinuation(std.mem.trimStart(u8, next_line, " \t"))) catch @panic("OOM");
            line_continues = hasContinuation(next_line);
        }
        return extractCcFlags(mk, gpa, recipe.items);
    }
    return null;
}

fn extractCcFlags(mk: Makefile, gpa: std.mem.Allocator, recipe: []const u8) ?[]const u8 {
    var start: usize = 0;
    var found = false;
    for ([_][]const u8{ "$(CC)", "$(LINKCC)" }) |tok| {
        if (std.mem.indexOf(u8, recipe, tok)) |idx| {
            start = idx + tok.len;
            found = true;
            break;
        }
    }
    if (!found) return null;
    const c_idx = std.mem.indexOf(u8, recipe[start..], " -c ") orelse return null;
    return mk.expand(gpa, recipe[start .. start + c_idx]);
}

/// Finds the single-line `Modules/<name>$(EXT_SUFFIX): <prereqs>; <recipe>`
/// rule that `makesetup` generated for a shared extension module, as produced
/// directly by `./configure` (no `make` involved).
pub fn findSharedModuleRule(mk: Makefile, gpa: std.mem.Allocator, module_name: []const u8) ?ModuleRule {
    const needle = std.fmt.allocPrint(gpa, "Modules/{s}$(EXT_SUFFIX):", .{module_name}) catch @panic("OOM");
    const idx = std.mem.indexOf(u8, mk.text, needle) orelse return null;
    const eol = std.mem.indexOfScalarPos(u8, mk.text, idx, '\n') orelse mk.text.len;
    const line = mk.text[idx..eol];
    const colon = std.mem.indexOfScalar(u8, line, ':') orelse return null;
    const semi = std.mem.indexOfScalar(u8, line, ';') orelse line.len;
    const prereqs_str = line[colon + 1 .. semi];
    const recipe_str = if (semi < line.len) line[semi + 1 ..] else "";
    return .{
        .prereqs = tokens(gpa, prereqs_str),
        .recipe = tokens(gpa, mk.expand(gpa, recipe_str)),
    };
}
